{
  "name": "Industrial Label Pro",
  "description": "A professional industrial labeling system with AI-powered safety data generation and QR code support."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface LabelData {
  id: string;
  productName: string;
  sku: string;
  batchNumber: string;
  manufactureDate: string;
  expiryDate: string;
  weight: string;
  description: string;
  safetyWarning: string;
  storageInstructions: string;
  qrContent: string;
}

export interface AIResponse {
  description: string;
  safetyWarning: string;
  storageInstructions: string;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AIResponse } from "../types";

// Initialize Gemini Client
// NOTE: Process.env.API_KEY is handled by the environment
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    description: {
      type: Type.STRING,
      description: "A short, technical industrial description of the product (max 150 chars). In Portuguese.",
    },
    safetyWarning: {
      type: Type.STRING,
      description: "Relevant GHS safety warnings or handling precautions (e.g., 'Corrosive', 'Fragile'). In Portuguese.",
    },
    storageInstructions: {
      type: Type.STRING,
      description: "Brief storage instructions (e.g., 'Store in cool dry place'). In Portuguese.",
    },
  },
  required: ["description", "safetyWarning", "storageInstructions"],
};

export const generateLabelDetails = async (productName: string): Promise<AIResponse> => {
  try {
    const prompt = `
      Você é um especialista em logística industrial e segurança do trabalho.
      Gere dados técnicos para uma etiqueta industrial baseada no seguinte nome de produto: "${productName}".
      Se o produto for perigoso, seja rigoroso nos avisos de segurança.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        systemInstruction: "You are an industrial labeling assistant. Always output in Portuguese.",
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response from AI");
    }

    return JSON.parse(text) as AIResponse;
  } catch (error) {
    console.error("Error fetching AI label details:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { PackageOpen, Zap } from 'lucide-react';
import { LabelForm } from './components/LabelForm';
import { LabelPreview } from './components/LabelPreview';
import { LabelData } from './types';
import { generateLabelDetails } from './services/geminiService';

const initialData: LabelData = {
  id: crypto.randomUUID().slice(0, 8).toUpperCase(),
  productName: '',
  sku: '',
  batchNumber: '',
  manufactureDate: new Date().toISOString().split('T')[0],
  expiryDate: '',
  weight: '',
  description: '',
  safetyWarning: '',
  storageInstructions: '',
  qrContent: ''
};

function App() {
  const [formData, setFormData] = useState<LabelData>(initialData);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleReset = () => {
    setFormData({
      ...initialData,
      id: crypto.randomUUID().slice(0, 8).toUpperCase(),
      manufactureDate: new Date().toISOString().split('T')[0],
    });
    setError(null);
  };

  const handleGenerateAI = async () => {
    if (!formData.productName) return;

    setIsGenerating(true);
    setError(null);

    try {
      const aiData = await generateLabelDetails(formData.productName);
      setFormData(prev => ({
        ...prev,
        description: aiData.description,
        safetyWarning: aiData.safetyWarning,
        storageInstructions: aiData.storageInstructions,
      }));
    } catch (err) {
      setError("Falha ao gerar dados com IA. Verifique sua conexão ou tente novamente.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header - Not visible in print */}
      <header className="bg-slate-900 text-white shadow-md no-print z-10">
        <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg">
              <PackageOpen className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">Etiqueta<span className="text-blue-400">Pro</span></h1>
              <p className="text-xs text-slate-400">Sistema Industrial Inteligente</p>
            </div>
          </div>
          <div className="flex items-center gap-2 text-sm text-slate-300">
             <Zap className="w-4 h-4 text-yellow-400" />
             <span>Powered by Gemini 2.5</span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow bg-slate-50 p-4 md:p-8">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Form (No Print) */}
          <div className="lg:col-span-5 no-print">
            <LabelForm 
              data={formData}
              onChange={handleInputChange}
              onGenerateAI={handleGenerateAI}
              isGenerating={isGenerating}
              onPrint={handlePrint}
              onReset={handleReset}
            />
            {error && (
              <div className="mt-4 p-4 bg-red-50 border border-red-200 text-red-700 rounded-lg text-sm">
                {error}
              </div>
            )}

            <div className="mt-6 bg-blue-50 p-4 rounded-lg border border-blue-100 text-sm text-blue-800">
              <h3 className="font-bold mb-1">Como usar:</h3>
              <ul className="list-disc list-inside space-y-1 text-blue-700">
                <li>Digite o nome do produto (ex: "Soda Cáustica").</li>
                <li>Clique em <strong>IA Auto</strong> para gerar avisos de segurança.</li>
                <li>Complete o lote e as datas.</li>
                <li>Clique em Imprimir.</li>
              </ul>
            </div>
          </div>

          {/* Right Column: Preview (Printable) */}
          <div className="lg:col-span-7 flex flex-col">
            <div className="no-print mb-4 flex justify-between items-center">
              <h2 className="text-lg font-semibold text-slate-700">Pré-visualização da Etiqueta</h2>
              <span className="text-xs bg-slate-200 text-slate-600 px-2 py-1 rounded">
                Dimensões aprox: 15cm x 10cm
              </span>
            </div>

            {/* The actual label component */}
            <LabelPreview data={formData} />
          </div>
        </div>
      </main>
    </div>
  );
}

export default App;
